from __future__ import print_function # Python 2/3 compatibility
import json,time,pymysql,os


"""
The main handler of our Lambda function receives an API Gateway event and returns a response. It then creates the SQL query from the event parameter inputs. Finally it runs the sql queries against the AWS MySQL database using pymysql.
"""

def lambda_handler(event, context):
    #print("Received event: " + json.dumps(event))

    if 'queryString' in event['body']:
        queryString = "SELECT * FROM PRODUCTS WHERE NAME LIKE %s"
        params = ( '%' + str(event["body"]["name"])  + '%')
    else :
        queryString = ""

    connection = pymysql.connect('HOST','USER', 'PASSWORD', 'DATABASE')
    cursor=connection.cursor()


    cursor.execute(queryString,params)
    results = [x for x in cursor]
    if len(results)>0:
    	return {
        "statusCode": 200,
        "body": json.dumps(str(results))
    }
    else : 
        return {
        'statusCode': 404,
        'body': 'There is no product found with this name'
    }